import React from 'react'
import "../Navigation/Nav.css"
import { Link } from 'react-router-dom'
import { useState, useEffect } from 'react'
import Logo from "../../assets/pikachu.png"




const Nav = () => {
  const [darkMode, setDarkMode] = useState(true);
  const [lightMode, setLightMode] = useState(true)
const toggleTheme = () => {
  const nextMode = darkMode; 
  setDarkMode(nextMode); 
  document.body.classList.toggle('light-mode'); 
  localStorage.setItem('theme', nextMode ? 'dark' : 'light'); 

}


useEffect(() => {
    const savedTheme = localStorage.getItem('theme'); 
    if (savedTheme === 'light') {
      setDarkMode(false); 
      document.body.classList.add('light-mode');
    }
  }, []);






  return (
    
    <nav>
 <div className="logo">
      <figure>
  <Link to="/"><img src={Logo} alt="" style={{ width: '50px' }}/></Link>
    </figure>
    </div>
   
    {/* NAV LINKS */}
   <div className="nav-links">
        <Link to="/">Home</Link>
        <Link to="/about">About</Link>
        <Link to="/contact">Contact</Link>
        <Link to="/feedback">Feedback</Link>
      </div>
     

    
<div className="nav-actions">
    <span style={{ color: 'red', border: '1px solid red' }}></span>
    <button onClick={toggleTheme}>{darkMode ? '☀️' : '🌙'}</button>
    <button onClick={toggleTheme}>{lightMode ? '🌙' : '☀️'}</button>
</div>

    </nav>
    
);
};

export default Nav
